function solve(s, k) {
    let L = 0;
    for (let i = 0; i < s.length; i++) {
        switch (s[i]) {
            case '*':
                if (L > 0) L--;
                break;
            case '#':
                L *= 2;
                break;
            case '%':
                break;
            default:
                L++;
        }
    }

    if (k >= L) {
        return '.';
    }

    for (let i = s.length - 1; i >= 0; i--) {
